VALUES
  ('disabled-6f0ba476-moex-00101', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '甲公司為兼營營業人，本期進項 2000 萬元，支付進項稅額 100 萬元，其 中有交際費200萬元，進項稅額10萬元，以及購買乘人小汽車280萬元， 進項稅額14萬元。本期內銷應稅貨物800萬元，銷項稅額40萬元，外銷 貨物 700 萬元，另銷售免稅貨物 1000 萬元。請根據以上資料採「比例扣 抵法」，計算甲公司本期營業稅額為何？', '["應退稅額20萬元", "應退稅額5萬6千元", "應退稅額4萬4千元，留抵次期20萬6千元", "留抵次期29萬4千元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00102', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '營業人銷售下列何項，非屬免徵營業稅？', '["土地", "房屋", "飼料", "麵粉"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00103', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '有關營業稅之申報繳納，下列敘述何者錯誤？', '["營業人因取得固定資產而溢付之營業稅，由主管稽徵機關查明後退還之", "外國之事業、機關、團體、組織在中華民國境內無固定營業場所而有銷 售勞務者，應由勞務買受人於給付報酬之次期開始 15 日內，就給付額 依規定稅率，計算營業稅額繳納之", "為減輕徵納雙方之行政負擔，營業人當期若無銷售額，則不需向主管稽 徵機關申報銷售額、溢付營業稅額", "營業人以每二月為一期，於次期開始15日內，填具規定格式之申報書， 檢附相關文件，向主管稽徵機關申報銷售額、應納或溢付營業稅額。但 若適用零稅率者，得申請以每月為一期報繳營業稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00104', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '營業人虛報進項稅額時，除追缴稅款外，應按所漏稅額處以多少倍罰鍰？', '["5倍以下", "1至10倍", "3至5倍", "5至10倍"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00105', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '考量我國將邁入超高齡社會，落實建構無障礙友善乘車環境及促進身心障 礙者、行動不便者之自立生活，照顧其行的需求，財政部爰於民國113年', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00106', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '月 18 日修正公布貨物稅條例第 12 條，延長購買身心障礙者復康巴士 以及載運輪椅使用者車輛之免徵貨物稅期限至：', '["116年12月31日止", "117年12月31日止", "118年12月31日止", "120年12月31日止"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00107', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '依我國遺產及贈與稅法規定，納稅義務人有故意以詐欺或其他不正當方 法，逃漏遺產稅或贈與稅者，除依繼承或贈與發生年度稅率重行核計補徵 外，並應處以下列何項處罰？', '["1萬5千元以下之罰鍰", "所漏稅額1倍至3倍之罰鍰", "核定應納稅額加處1倍至2倍之罰鍰", "1年以下有期徒刑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00108', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '甲為現役軍人於民國 113 年 6 月 13 日因軍事演習身亡，其名下遺產有存 款800萬元，A上市股票100張共計5800萬元，及B、C二筆土地，土地 公告現值總計5000萬元。其中B、C二筆土地係甲於110年9月10日繼 承其父之遺產，且已繳納遺產稅。另甲死亡時遺有三名已成年子女以及重 度殘障之母親。試根據以上資料計算甲之遺產稅額為何？', '["293萬5千元", "919萬5千5百元", "279萬7千元", "413萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00109', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '甲於民國 108 年 5 月以 900 萬元購進 A 地供營業用，以公告現值 560 萬 元申報移轉現值，後於110年3月贈與給其妻乙，以公告現值820萬元申 報移轉現值，並依規定申請不課徵土地增值稅。乙於113年8月出售該地 予丙，售價為1800萬元，以公告現值1050萬元申報移轉現值。物價指數 調整率為 120%，根據上述資料，試問此交易之納稅義務人及土地增值稅 應納稅額為何？', '["納稅義務人為乙，土地增值稅應納稅額為75萬6千元", "納稅義務人為甲，土地增值稅應納稅額為98萬元", "納稅義務人為丙，土地增值稅應納稅額為46萬元", "納稅義務人為丙，土地增值稅應納稅額為13萬2千元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00110', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9bdab6d6', 'sub-disabled-6f0ba476-04', NULL, 'single_choice', '甲於民國113年8月5日出售其位於臺北市之自用住宅用地A地1公畝， 售價2500萬元，以公告現值1600萬元申報為移轉現值，並繳納土地增值 稅 70 萬元。同年 11 月又以 2000 萬元重購臺北市之自用住宅用地 B 地 1 公畝，以公告現值 1000 萬元申報為移轉現值。試問，甲是否可申請退還 土地增值稅，若可退還則可退還多少稅額？', '["因在2年內重購，故可申請退稅43萬7千5百元", "因在2年內重購，故可申請退稅7萬元", "因在2年內重購，故可申請退稅3萬5千元", "無法申請退稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "7ef3c7ffd7ec", "answer_pdf_sha1": "96cfd7d15769", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
